  // <= X, since usub.sat either returns X - C (when X >= C) or 0.
  if (match(V, m_Intrinsic<Intrinsic::usub_sat>(m_Value(Op0), m_ConstantInt(CI)))) {
    if (!CI->isNegative() && !CI->isZero()) {
      // usub.sat(X, C) where C > 0 produces a result <= X.
      // We can decompose it as X - C with a precondition that X >= C.
      Preconditions.emplace_back(
          CmpInst::ICMP_UGE, Op0,
          ConstantInt::get(Op0->getType(), CI->getZExtValue()));
      auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
      auto ResB = decompose(CI, Preconditions, IsSigned, DL);
      ResA.sub(ResB);
      return ResA;
    }
  }

  return {V, IsKnownNonNegative};
}
CODEEOF"}

